#!/usr/bin/env python3
import json
from pathlib import Path

def write_batch(batch, frame_url, items):
    out = Path(__file__).resolve().parent.parent / '.flow-captures/miro-flow-full/upload-batches' / f'{batch}-responses.json'
    data = [{"slug": s, "frameUrl": frame_url, "token": t, "upload_url": u} for s, t, u in items]
    out.write_text(json.dumps(data, indent=2))
    print(json.dumps({"batch": batch, "count": len(data)}))

